import{j as a,b as l,c as i,aa as r}from"./chunks/framework.Bxf40uRC.js";const b=JSON.parse('{"title":"面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"操作系统/面试问题.md","filePath":"操作系统/面试问题.md","lastUpdated":null}'),t={name:"操作系统/面试问题.md"},o=r('<h1 id="面试问题" tabindex="-1">面试问题 <a class="header-anchor" href="#面试问题" aria-label="Permalink to &quot;面试问题&quot;">​</a></h1><h2 id="进程和线程的区别" tabindex="-1">进程和线程的区别？ <a class="header-anchor" href="#进程和线程的区别" aria-label="Permalink to &quot;进程和线程的区别？&quot;">​</a></h2><ul><li>基本概念：进程是操作系统资源分配的最小单位，线程是操作系统调度的最小单位；</li><li>资源共享：每个进程都有自己独立的代码、数据和资源空间(进程上下文)，而同一进程内的线程共享进程的资源；</li><li>通信：进程间通信，需要操作系统提供特定的机制，如管道、消息队列等，效率相对比较低；线程间通信可以直接通过读写进程数据段来进行，效率较高；</li><li>开销：进程创建或者销毁的开销远大于线程，进程间切换的开销也远大于线程；</li></ul><h2 id="线程共用进程的哪些资源" tabindex="-1">线程共用进程的哪些资源？ <a class="header-anchor" href="#线程共用进程的哪些资源" aria-label="Permalink to &quot;线程共用进程的哪些资源？&quot;">​</a></h2><ul><li><p><strong>代码段</strong>：存放程序的执行代码；</p></li><li><p><strong>数据段</strong>：包括全局变量、静态变量等；</p></li><li><p><strong>堆空间</strong>：用于动态内存分配；</p></li><li><p><strong>文件描述符表</strong>：打开文件、网络连接的标识符；</p></li><li><p><strong>信号处理器</strong>：信号及其对应的处理方式；</p></li></ul><h2 id="多进程和多线程的优缺点" tabindex="-1">多进程和多线程的优缺点？ <a class="header-anchor" href="#多进程和多线程的优缺点" aria-label="Permalink to &quot;多进程和多线程的优缺点？&quot;">​</a></h2><h4 id="多进程" tabindex="-1">多进程 <a class="header-anchor" href="#多进程" aria-label="Permalink to &quot;多进程&quot;">​</a></h4><p>优点：稳定性高，一个进程崩溃不会直接影响到其他进程；</p><p>缺点：资源消耗大，进程间通信复杂；</p><h4 id="多线程" tabindex="-1">多线程 <a class="header-anchor" href="#多线程" aria-label="Permalink to &quot;多线程&quot;">​</a></h4><p>优点：创建、销毁的开销小，资源消耗少，线程通信简单；</p><p>缺点：稳定性比较差，一个线程崩溃可能影响整个进程，需要处理同步和竞态条件；</p><h2 id="操作系统堆和栈的区别" tabindex="-1">操作系统堆和栈的区别？ <a class="header-anchor" href="#操作系统堆和栈的区别" aria-label="Permalink to &quot;操作系统堆和栈的区别？&quot;">​</a></h2><ul><li>堆：动态分配的内存，生命周期由程序员控制，容易产生内存泄露；</li><li>栈：自动管理的内存区域，存储函数调用的参数，局部变量等，生命周期由编译器控制，速度快但是空间有限；</li></ul><h2 id="堆和栈哪个快" tabindex="-1">堆和栈哪个快？ <a class="header-anchor" href="#堆和栈哪个快" aria-label="Permalink to &quot;堆和栈哪个快？&quot;">​</a></h2><p>栈比堆快：</p><ul><li>管理方式：栈由操作系统自动分配和释放，支持快速的数据访问和存储；堆的分配和释放由程序控制，涉及到更复杂的内存管理(如寻找合适的内存块)</li><li>存储特性：栈遵循先进后出，容易管理；堆内存是随机分配和释放的，容易产生碎片，影响性能；</li></ul><h2 id="在代码中堆和栈的内存上限大概有多少" tabindex="-1">在代码中堆和栈的内存上限大概有多少？ <a class="header-anchor" href="#在代码中堆和栈的内存上限大概有多少" aria-label="Permalink to &quot;在代码中堆和栈的内存上限大概有多少？&quot;">​</a></h2><ul><li>栈：默认在几百kb到几Mb之间；例如windows默认1Mb，Linux默认8Mb；</li><li>堆：理论上受到系统可用内存的限制。在32系统上，可寻址空间大概4GB，但实际可用堆空间会小于这个值；在64位操作系统中，进程的虚拟内存地址空间远远大于物理内存大小，理论上可以支持上TB级别的虚拟内存。实际可用的堆大小依然受到物理内存和操作系统配置的限制；</li></ul><h2 id="协程和线程的区别" tabindex="-1">协程和线程的区别？ <a class="header-anchor" href="#协程和线程的区别" aria-label="Permalink to &quot;协程和线程的区别？&quot;">​</a></h2><h3 id="调度机制" tabindex="-1">调度机制 <a class="header-anchor" href="#调度机制" aria-label="Permalink to &quot;调度机制&quot;">​</a></h3><ul><li><strong>线程</strong>：线程的调度由操作系统内核管理，是抢占式的。这意味着操作系统决定何时中断线程，切换到另一个线程。线程可以运行在多个CPU核心上，实现真正的并行计算。</li><li><strong>协程</strong>：协程通常由程序在用户态管理，是协作式的。一个协程必须显式地让出控制权，另一个协程才能开始执行，这通常通过协程库中的yield操作实现。因此，协程的切换和调度不涉及内核态到用户态的切换，减少了开销。</li></ul><h3 id="并发与并行" tabindex="-1">并发与并行 <a class="header-anchor" href="#并发与并行" aria-label="Permalink to &quot;并发与并行&quot;">​</a></h3><ul><li><strong>线程</strong>：线程可以实现真正的并行执行，尤其是在多核CPU上。线程被操作系统调度到不同的CPU核心，各个线程可以同时执行。</li><li><strong>协程</strong>：协程主要用于实现并发。虽然协程在单核CPU上运行时只能顺序执行，但由于切换开销极小，给人以“同时执行”的错觉。在多核CPU上，通过在每个核心上运行多个线程，每个线程中运行多个协程，可以实现高效的并发处理。</li></ul><h3 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h3><ul><li><strong>线程</strong>：适用于CPU密集型任务、需要真正并行执行的场景，以及操作系统已经提供了良好线程支持的情况。</li><li><strong>协程</strong>：非常适合I/O密集型任务、大量等待任务完成的场景（如网络请求、数据库操作），以及需要处理大量并发连接的服务器开发。</li></ul><h2 id="操作系统内存不足会发生什么" tabindex="-1">操作系统内存不足会发生什么？ <a class="header-anchor" href="#操作系统内存不足会发生什么" aria-label="Permalink to &quot;操作系统内存不足会发生什么？&quot;">​</a></h2><p>当操作系统的内存不足时，即系统的可用物理内存资源低于当前需求，操作系统会采取一系列措施来管理这种资源紧张的情况。这些措施旨在维持系统运行，但可能会导致性能下降。主要的措施包括内存替换（或称为分页、交换）等策略：</p><h3 id="_1-内存分页-paging" tabindex="-1">1. 内存分页（Paging） <a class="header-anchor" href="#_1-内存分页-paging" aria-label="Permalink to &quot;1. 内存分页（Paging）&quot;">​</a></h3><p><strong>分页机制</strong>：操作系统会将内存分为多个固定大小的页。当内存不足时，操作系统会选择一些当前不活跃的页（即那些最近没有被访问或很少访问的页），将它们移动到磁盘上的交换空间（或称为交换文件），这个过程称为&quot;分页&quot;。</p><h3 id="_2-内存交换-swapping" tabindex="-1">2. 内存交换（Swapping） <a class="header-anchor" href="#_2-内存交换-swapping" aria-label="Permalink to &quot;2. 内存交换（Swapping）&quot;">​</a></h3><p><strong>整体交换</strong>：在一些操作系统中，还可能采用将整个进程的内存空间移动到交换空间的做法。这通常发生在系统极度缺乏内存时。当进程需要再次运行时，操作系统会将其数据从交换空间换回到物理内存。</p><h3 id="_3-内存压缩" tabindex="-1">3. 内存压缩 <a class="header-anchor" href="#_3-内存压缩" aria-label="Permalink to &quot;3. 内存压缩&quot;">​</a></h3><p><strong>内存压缩</strong>：一些现代操作系统采用内存压缩技术，将内存中的一些数据进行压缩，以减少所需的物理内存量。这可以在一定程度上减轻内存不足的情况，但会增加CPU的负担，因为需要对数据进行压缩和解压缩。</p><h2 id="线程之间的通讯方式" tabindex="-1">线程之间的通讯方式？ <a class="header-anchor" href="#线程之间的通讯方式" aria-label="Permalink to &quot;线程之间的通讯方式？&quot;">​</a></h2><ul><li><strong>互斥锁</strong>：允许只有一个线程同时访问被保护的临界区(共享资源)</li><li><strong>条件变量</strong>：条件变量用于线程间通信，允许一个线程等待某个条件满足，而其他线程可以发出信号通知等待线程。通常与互斥锁一起使用；</li><li><strong>读写锁</strong>：读写锁允许多个线程同时读取共享资源，但是只允许一个线程写入资源；</li><li><strong>信号量</strong>：用于控制多个线程对共享资源进行访问的工具；</li></ul><h2 id="进程间通讯的方式" tabindex="-1">进程间通讯的方式？ <a class="header-anchor" href="#进程间通讯的方式" aria-label="Permalink to &quot;进程间通讯的方式？&quot;">​</a></h2><p>线程间的通信目的主要是用于线程同步，所以线程没有像进程通信中的用于数据交换的通信机制。</p><ul><li><strong>管道</strong>：管道是一种半双工的通信方式，数据只能单向流动，而且只能在具有亲缘关系的进程间使用。进程的亲缘关系通常是指父子进程关系。</li><li><strong>有名管道</strong>：有名管道也是半双工的通信方式，但是它允许无亲缘关系进程间的通信。</li><li><strong>信号量</strong>：信号量是一个计数器，可以用来控制多个进程对于共享资源的访问。它常作为一种锁的机制，防止某进程正在访问共享资源时，其他进程也访问该资源。因此，主要作为进程间以及同一进程内不同线程之间的同步手段；</li><li><strong>消息队列</strong>：消息队列是由消息的链表，存放在内核中并且由消息队列标识符标识。消息队列克服了信号传递信息少，管道只能承载无格式字节流以及缓冲区大小受限制等缺点；</li><li><strong>信号</strong>：信号是一种比较复杂的通信方式，用于通知接收进程某个事件已经发生；</li><li><strong>共享内存</strong>：共享内存就是映射一段能被其他进程能够访问的内存，这段共享内存由一个进程创建，但多个进程都可以访问。共享内存是最快的IPC(进程间通信)方式；往往与其他通信机制，如信号量，配合使用，来实现进程间的同步和通信；</li><li><strong>套接字</strong>：也是一种通信方式，不过与其他通信机制不同的是，它可以用于不同设备之间的进程通讯；</li></ul>',39),e=[o];function n(s,h,d,u,g,c){return l(),i("div",null,e)}const q=a(t,[["render",n]]);export{b as __pageData,q as default};
